-- Ogrenciler tablosu olusturma
CREATE TABLE students (
    id INT PRIMARY KEY AUTO_INCREMENT,
    name VARCHAR(50) NOT NULL,
    age INT,
    grade DECIMAL(5,2),
    email VARCHAR(100) UNIQUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Kurslar tablosu olusturma
CREATE TABLE courses (
    id INT PRIMARY KEY AUTO_INCREMENT,
    title VARCHAR(100) NOT NULL,
    credit INT DEFAULT 3
);

-- Tabloyu silme (eger varsa)
DROP TABLE IF EXISTS old_students;

-- Mevcut tabloya kolon ekleme
ALTER TABLE students ADD phone VARCHAR(15);

-- Kolon turunu degistirme
ALTER TABLE students MODIFY grade DECIMAL(6,2);
